1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { op: "quote"; items: Item[] };
14	type Input = { customer: { yearsWithMHPCO: number }; steps: Step[] };
15	
16	const COMPONENT_BLOCK_SIZE = 3;
17	const COMPONENT_BLOCK_PREMIUM = 60;
18	
19	const basePremium = (items: Item[]): number => {
20	  if (items.length === COMPONENT_BLOCK_SIZE && items.every((i) => i.type === "rune")) {
21	    return COMPONENT_BLOCK_PREMIUM;
22	  }
23	  return items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
24	};
25	
26	const percentOf = (amount: number, percent: number): number =>
27	  (amount * percent) / 100;
28	
29	const firstInsuranceSurcharge = (base: number): number =>
30	  Math.ceil(percentOf(base, FIRST_INSURANCE_SURCHARGE_PERCENT));
31	
32	const quotePremium = (items: Item[]): number => {
33	  const base = basePremium(items);
34	  return base + firstInsuranceSurcharge(base) + PROCESSING_FEE;
35	};
36	
37	const executeStep = ({ items }: Step) => ({ premium: quotePremium(items) });
38	
39	export const run = (input: unknown): unknown => {
40	  const { steps } = input as Input;
41	  return { results: steps.map(executeStep) };
42	};
